const aarrData = {
  acquisition: { cpi: 1800, monthlyInstalls: 8000 },
  activation: { day1Retention: 18 },
  retention: { day30Retention: 4 },
  revenue: { payingRate: 2.5, arpu: 950 },
  referral: { shareRate: 3 }
};

function diagnoseAARRR(data) {
  const issues = [];

  if (data.activation.day1Retention < 15) {
    issues.push({ phase: 'Activation', level: '問題あり', reason: 'Day1 Retentionが15%未満' });
  } else if (data.activation.day1Retention < 20) {
    issues.push({ phase: 'Activation', level: '要注意', reason: 'Day1 Retentionが20%未満' });
  } else {
    issues.push({ phase: 'Activation', level: '正常', reason: 'Day1 Retentionが良好' });
  }

  if (data.retention.day30Retention < 3) {
    issues.push({ phase: 'Retention', level: '問題あり', reason: 'Day30 Retentionが3%未満' });
  } else if (data.retention.day30Retention < 5) {
    issues.push({ phase: 'Retention', level: '要注意', reason: 'Day30 Retentionが5%未満' });
  } else {
    issues.push({ phase: 'Retention', level: '正常', reason: 'Day30 Retentionが良好' });
  }

  if (data.revenue.payingRate < 1) {
    issues.push({ phase: 'Revenue', level: '問題あり', reason: '課金転換率が1%未満' });
  } else if (data.revenue.payingRate < 3) {
    issues.push({ phase: 'Revenue', level: '要注意', reason: '課金転換率が3%未満' });
  } else {
    issues.push({ phase: 'Revenue', level: '正常', reason: '課金転換率が良好' });
  }

  return issues;
}

const diagnosis = diagnoseAARRR(aarrData);
diagnosis.forEach(d => {
  console.log(`[${d.phase}] ${d.level}: ${d.reason}`);
});
